mapper.update:
update clazz
name = #{name} , room = #{room} , begin_date = #{beginDate} , end_date = #{endDate} , master_id = #{masterId} , subject = #{subject} ,
where id =#{id};

mapper.select:
select clazz.id , clazz.name , clazz.room , clazz.begin_date, clazz.end_date, clazz.master_id, clazz.create_time, clazz.update_time, emp.name as master_name from clazz left join emp on clazz.master_id = emp.id
clazz.name like concat('%', #{name}, '%')
and clazz.begin_date > #{begin} and clazz.end_date < #{end}
